{% set s = frappe.get_doc('iHotel Settings', 'iHotel Settings') %}
{% set hotel = s.hotel_name or 'iHotel' %}
{% set currency = s.currency or '' %}
{% set ci_time = (s.default_check_in_time or '14:00:00')[:5] %}
{% set co_time = (s.default_check_out_time or '12:00:00')[:5] %}
{% set signatory = s.hotel_signatory_name or ('The ' + hotel + ' Team') %}
{% set sign_title = s.hotel_signatory_title or '' %}
{% set pax = (doc.adults or 1)|string + ' Adult(s)' %}
{% if doc.children %}{% set pax = pax + ' / ' + doc.children|string + ' Child(ren)' %}{% endif %}
{% set room_pax = (doc.room_type or '-') + ' / ' + pax %}
{% if doc.no_of_rooms and doc.no_of_rooms > 1 %}{% set room_pax = doc.no_of_rooms|string + '-' + room_pax %}{% endif %}
{% set rate_label = doc.rate_type or '' %}
{% if doc.rate_type %}
  {% set rt = frappe.get_doc('Rate Type', doc.rate_type) %}
  {% if rt.rate_type_name %}{% set rate_label = rt.rate_type_name %}{% endif %}
{% endif %}
{% set rate_str = frappe.utils.fmt_money(doc.rent or 0, currency=currency) + ' per night' %}
{% if rate_label %}{% set rate_str = rate_str + ' (' + rate_label + ')' %}{% endif %}
{% set payment = doc.payment_method or '-' %}
{% if doc.credit_card_type %}{% set payment = doc.credit_card_type %}{% if doc.credit_card_last4 %}{% set payment = payment + ' ending ' + doc.credit_card_last4 %}{% endif %}{% endif %}
{% set arr_time = (doc.eta or doc.check_in_time or '') %}
{% if arr_time %}{% set arr_time = arr_time[:5] %}{% else %}{% set arr_time = 'Please advise' %}{% endif %}
{% set prefs = doc.special_requests or 'Please advise with any preferences' %}
{% set source = doc.business_source_category or '-' %}
<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="margin:0;padding:0;background:#f4f4f5;font-family:'Segoe UI',Arial,sans-serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#f4f4f5;padding:32px 16px;">
  <tr><td align="center">
    <table width="600" cellpadding="0" cellspacing="0" style="background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,.1);">

      <!-- Header -->
      <tr>
        <td style="background:#1e3a5f;padding:24px 32px;">
          <h1 style="margin:0;color:#fff;font-size:22px;font-weight:600;letter-spacing:.5px;">{{ hotel }}</h1>
          <p style="margin:4px 0 0;color:#a8c4e0;font-size:13px;">Reservation Confirmation Letter</p>
        </td>
      </tr>

      <!-- Body -->
      <tr><td style="padding:32px;">

        <p style="margin:0 0 6px;font-size:13px;color:#6c757d;">Date: {{ frappe.utils.formatdate(frappe.utils.nowdate(), 'dd-MMM-yyyy')|upper }}</p>

        <p style="margin:0 0 16px;font-size:16px;color:#212529;">Dear <strong>{{ doc.full_name or 'Guest' }}</strong>,</p>

        <p style="margin:0 0 20px;font-size:14px;color:#495057;line-height:1.6;">
          Thank you for choosing <strong>{{ hotel }}</strong>. Please print or save this letter to present upon check-in.
        </p>

        <!-- Reservation Details -->
        <h3 style="margin:0 0 10px;font-size:14px;color:#1e3a5f;border-bottom:1px solid #dee2e6;padding-bottom:4px;">Reservation Details</h3>
        <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin-bottom:16px;">
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;width:170px;">Confirmation No.</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;font-weight:600;">{{ doc.name }}</td></tr>
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;">Guest Name</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;font-weight:500;">{{ doc.full_name or '-' }}</td></tr>
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;">Source</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;font-weight:500;">{{ source }}</td></tr>
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;">Arrival Date</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;font-weight:500;">{{ frappe.utils.formatdate(doc.check_in_date, 'dd-MMM-yyyy')|upper if doc.check_in_date else '-' }}</td></tr>
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;">Departure Date</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;font-weight:500;">{{ frappe.utils.formatdate(doc.check_out_date, 'dd-MMM-yyyy')|upper if doc.check_out_date else '-' }}</td></tr>
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;">Number of Nights</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;font-weight:500;">{{ doc.days or '-' }}</td></tr>
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;">Room Type / PAX</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;font-weight:500;">{{ room_pax }}</td></tr>
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;">Room Rate</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;font-weight:500;">{{ rate_str }}</td></tr>
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;">Payment</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;font-weight:500;">{{ payment }}</td></tr>
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;">Arrival Time</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;font-weight:500;">{{ arr_time }}</td></tr>
          <tr><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:13px;">Preferences</td><td style="padding:7px 0;border-bottom:1px solid #f0f0f0;color:#212529;font-size:13px;">{{ prefs }}</td></tr>
        </table>

        <!-- Included Services -->
        {% if s.included_services %}
        <h3 style="margin:0 0 8px;font-size:14px;color:#1e3a5f;border-bottom:1px solid #dee2e6;padding-bottom:4px;">Included Services &amp; Facilities</h3>
        <ul style="margin:0 0 16px;padding-left:20px;">
          {% for line in s.included_services.strip().splitlines() %}{% if line.strip() %}
          <li style="margin:4px 0;font-size:13px;color:#495057;">{{ line.strip() }}</li>
          {% endif %}{% endfor %}
        </ul>
        {% endif %}

        <!-- Check-In / Check-Out -->
        <h3 style="margin:0 0 8px;font-size:14px;color:#1e3a5f;border-bottom:1px solid #dee2e6;padding-bottom:4px;">Check-In / Check-Out</h3>
        <p style="margin:0 0 4px;font-size:13px;color:#495057;">
          Standard Check-In: <strong>{{ ci_time }}</strong> &nbsp;|&nbsp; Standard Check-Out: <strong>{{ co_time }}</strong>
        </p>
        {% if s.late_checkout_policy %}
        <p style="margin:0 0 16px;font-size:13px;color:#495057;line-height:1.5;"><em>Late Check-Out:</em> {{ s.late_checkout_policy }}</p>
        {% else %}
        <br>
        {% endif %}

        <!-- Policies -->
        {% if s.cancellation_policy or s.airport_transfer_policy or s.booking_guarantee_policy %}
        <h3 style="margin:0 0 8px;font-size:14px;color:#1e3a5f;border-bottom:1px solid #dee2e6;padding-bottom:4px;">Policies</h3>
        {% if s.cancellation_policy %}
        <p style="margin:0 0 4px;font-size:13px;font-weight:600;color:#1e3a5f;">Cancellation Policy</p>
        <p style="margin:0 0 12px;font-size:13px;color:#495057;line-height:1.5;">{{ s.cancellation_policy }}</p>
        {% endif %}
        {% if s.airport_transfer_policy %}
        <p style="margin:0 0 4px;font-size:13px;font-weight:600;color:#1e3a5f;">Airport Transfer</p>
        <p style="margin:0 0 12px;font-size:13px;color:#495057;line-height:1.5;">{{ s.airport_transfer_policy }}</p>
        {% endif %}
        {% if s.booking_guarantee_policy %}
        <p style="margin:0 0 4px;font-size:13px;font-weight:600;color:#1e3a5f;">Booking Guarantee</p>
        <p style="margin:0 0 12px;font-size:13px;color:#495057;line-height:1.5;">{{ s.booking_guarantee_policy }}</p>
        {% endif %}
        {% endif %}

        <!-- Signatory -->
        <p style="margin:24px 0 0;font-size:14px;color:#212529;">
          Best Regards,<br>
          <strong>{{ signatory }}</strong>
          {% if sign_title %}<br><em style="font-size:12px;color:#6c757d;">{{ sign_title }}</em>{% endif %}
        </p>

        <!-- Data Privacy -->
        {% if s.data_privacy_notice %}
        <p style="margin:20px 0 0;font-size:11px;color:#6c757d;line-height:1.5;border-top:1px solid #e9ecef;padding-top:12px;">
          {{ s.data_privacy_notice }}
        </p>
        {% endif %}

      </td></tr>

      <!-- Footer -->
      <tr>
        <td style="background:#f8f9fa;padding:16px 32px;border-top:1px solid #e9ecef;">
          <p style="margin:0;font-size:12px;color:#6c757d;text-align:center;">This is an automated message from {{ hotel }}. Please do not reply directly to this email.</p>
        </td>
      </tr>

    </table>
  </td></tr>
</table>
</body>
</html>
